var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`레지나, 아빠는 호수를 찾으러 가셨다고 몇 번이나 말했잖니.`,JPN:`レジーナ、お父様は湖を探しに行ったって何度も言ったでしょう。`,ENG:`Regina, how many times do I have to tell you? Dad has gone looking for the Lake.`,TWN:`蕾佳娜，我說了好幾次，爸爸去找湖了吧。`},stage:{bg:`ROOM_02`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`호수 얘기는 이제 듣기 싫어! 아빠 보고 싶단 말이야!`,JPN:`湖の話なんてもう聞きたくない！　パパに会いたいの！`,ENG:`I don't want to hear about the Lake anymore! I miss Dad!`,TWN:`我不想再聽湖的事情了！我想見爸爸！`},stage:{bg:`ROOM_02`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`소란 떨지 말렴.`,JPN:`大声を出さないでちょうだい。`,ENG:`Don't be such a crybaby.`,TWN:`不可以大吵大鬧的。`},stage:{bg:`ROOM_02`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`넌 학회의 후계자야. 품위를 지켜야지.`,JPN:`あなたは学会の後継者なのよ。品位を保たないと。`,ENG:`You're the heir of the Society. Behave yourself.`,TWN:`妳是學會的繼承者，必須要保持禮儀。`},stage:{bg:`ROOM_02`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:null,text:{KOREA:`아빠?`,JPN:`パパ？`,ENG:`Dad?`,TWN:`爸爸？`},stage:{bg:`ROOM_02`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:null,text:{KOREA:`엄마, 아빠가 왔나 봐!`,JPN:`ママ！　パパが来たみたい！`,ENG:`Mom, Dad's home!`,TWN:`媽媽，爸爸好像回來了！`},stage:{bg:`ROOM_02`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:null,text:{KOREA:`기다려, 아빠! 내가 지금 문 열어 줄게!`,JPN:`待って、パパ！　私が今門を開けてあげるから！`,ENG:`Wait, Dad! I'm coming to the door!`,TWN:`等等，爸爸！我現在就幫你開門！`},stage:{bg:`ROOM_02`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`OCTOPUS_ESPR_NULL_NULL`,text:{KOREA:`레...... 지나......`,JPN:`レ……ジーナ……`,ENG:`Re... gina...`,TWN:`蕾……佳娜……`},stage:{bg:`ROOM_02`,slots:{L:null,C:{char_id:`OCTOPUS_ESPR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`힉......?!`,JPN:`ひッ……！？`,ENG:`Hic...`,TWN:`咿……？！`},stage:{bg:`ROOM_02`,slots:{L:null,C:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`OCTOPUS_ESPR_NULL_NULL`,text:{KOREA:`아빠...... 아빠란다...... 내...... 딸......`,JPN:`パパ……パパだよ……レ……ジーナ……`,ENG:`It's Daddy... It's your Daddy... my baby...`,TWN:`爸爸……是爸爸啊……我的……女兒……`},stage:{bg:`ROOM_02`,slots:{L:null,C:{char_id:`OCTOPUS_ESPR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`OCTOPUS_ESPR_NULL_NULL`,text:{KOREA:`레...... 지나...... 호수를...... 찾아선 안...... 돼......`,JPN:`レジ……ナ……湖を……探しては……いけな…………`,ENG:`Regina... You must... not... find... the lake...`,TWN:`蕾……佳娜……不能去……找……湖……`},stage:{bg:`ROOM_02`,slots:{L:null,C:{char_id:`OCTOPUS_ESPR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`어, 어머니? 지금...... 뭘 하시는 거죠?`,JPN:`お、お母様？　……何をしているの？`,ENG:`M-Mother? What... are you doing?`,TWN:`母、母親？您……在做什麼？`},stage:{bg:`ROOM_02`,slots:{L:null,C:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`설마 아버지를...... 아버지를 잡아먹는 건가요......?`,JPN:`まさか、お父様を……食べてるの……？`,ENG:`You're not... You're not feeding on Father, are you?`,TWN:`您該不會……把父親吃掉了……？`},stage:{bg:`ROOM_02`,slots:{L:null,C:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:null,text:{KOREA:`이건 이제 네 아버지가 아냐. 학회를 배신한 변절자일 뿐이지.`,JPN:`これはもうあなたの父じゃないの。学会の裏切者よ。`,ENG:`This isn't your father anymore. It's a filthy traitor who turned his back on the Society.`,TWN:`他現在不是妳的父親了，他只是個背叛學會的叛徒而已。`},stage:{bg:`ROOM_02`,slots:{L:null,C:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:null,text:{KOREA:`다 <color=#ff3636>네 아</color>비 탓이야. 그 더러<color=#ff3636>운 피</color>가 네게도 열등한 기<color=#ff3636>질을 물</color>려 주고 말았어.`,JPN:`全<color=#ff3636>てはあなたの父</color>親のせいよ。その汚<color=#ff3636>い血</color>のせいで、あなたも卑しい気<color=#ff3636>質を受け</color>継いでしまったの。`,ENG:`This is all <color=#ff3636>your fa</color>ther's fault. His dir<color=#ff3636>ty</color>, impure blood runs in you veins... He left his in<color=#ff3636>feriorities</color> within you!`,TWN:`都是<color=#ff3636>妳父</color>親的錯。他那<color=#ff3636>骯髒的血</color>液，讓妳都染上了劣<color=#ff3636>等的氣</color>質。`},stage:{bg:`ROOM_02`,slots:{L:null,C:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`더러운 건 당신이겠지!`,JPN:`汚いのはあなたよ！`,ENG:`You're the dirty one!`,TWN:`骯髒的是妳吧！`},stage:{bg:`ROOM_02`,slots:{L:null,C:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};